import{_ as a,o as p,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"灵力","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/灵力.md","filePath":"4.资源分区/5.能量池/灵力.md"}'),o={name:"4.资源分区/5.能量池/灵力.md"};function b(d,e,l,i,_,c){return p(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"灵力",tabindex:"-1"},[n("灵力 "),r("a",{class:"header-anchor",href:"#灵力","aria-label":'Permalink to "灵力"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004C")])])],-1),s('<h1 id="灵力-1" tabindex="-1">灵力 <a class="header-anchor" href="#灵力-1" aria-label="Permalink to &quot;灵力&quot;">​</a></h1><p>灵力<br> 东方通用能量<br> 灵力为人与灵魂达到和谐同调后产生的独有能量，往往被用于搭建沟通自身与灵魂的桥梁。<br> 每个人都拥有灵力，灵力是潜藏于人类身体与灵魂深处的宝藏。<br> 主神空间所给予的灵力池仅是将这份宝藏浅显地挖掘一二，并不能代表每个人对灵力的最终潜力。</p><p>灵力能量池的关键属性为智力+决心</p><p>恢复方式：灵力能量池不得以任何除自然恢复以外的手段进行恢复，包括但不限于冥想等。</p><p>恢复灵力需要进行一次长休，这次长休中包含一次不低于6小时的充分睡眠以及一顿饱饭。若使用者具有可以无需睡眠和进食的强化，也至少需要4小时睡眠专门供给灵力恢复。灵力修行者饭量为常人的X倍（X=D2/C3/B4/A5），无需进食的强化可将饭量减半。<br> 每次满足条件的长休将会使使用者的灵力恢复至上限。</p><p>灵力虽然无法被长休息外的方式所恢复，但却可以超出上限使用，当你灵力不足以支付（使用灵力的）能量消耗时，你可以强行透支自己的灵力能量池以满足该能力的灵力消耗。若如此做，你每以此方式透支了1点灵力，你就会承受1点不可避免的【灵感疲劳】。只要灵力修行者透支使用灵力，便至少获得1点灵感疲劳。<br> 透支的灵力能量数不得高于灵力能量池上限的两倍。</p><p>【灵感疲劳】：这是灵力修习者透支灵力而获得的特殊异常点数。灵感疲劳不会被异常点数恢复方式所减少/恢复。<br> 灵力修行者每获得1点灵感疲劳，其灵力能量池上限就会减少1点，当长休息结束后减少的灵力上限才能恢复。<br> 灵感疲劳在计算负面效果、严重与毁灭性后果时，等同于异常点数-疲乏。<br> 灵感疲劳在长休息后会全数移除。</p><p>灵力乃是每一个人类天生具有的宝藏，这份宝藏的开采与挖掘虽然与使用者的努力有关，但并不代表其未被挖掘的部分不存在。在紧要关头，灵力使用者常常能爆发出惊人的顽强意志！</p><p>灵力的基本用法：<br> 支付2点灵力，你在一轮内具有灵感视觉。</p><p>特别说明：若使用者因某种强化或负面效果影响而永远地失去了睡眠/饮食能力，那么他将失去灵力能量池。</p><p>觉醒灵力<br> D+500</p><p>你开启灵力能量池</p><p>你的智力每具有1点附加成功则灵力池上限扩大5点。</p><p>C+1000</p><p>灵力能量池上限增加【关键属性】点。</p><p>现在你在进行短休息时，可以移除3点灵感疲劳。</p><p>你获得新的灵力基本用法：<br> 在进行攻击时自由动作支付3点灵力，此次攻击转为精神伤害并以意志豁免。你可以将此能力灵力消耗翻倍，若如此做，则本能力可以对触及范围内的物体以迅捷动作使用，该物品在一小时内获得将攻击转为精神伤害并以意志豁免的效果。</p><p>灵力技能树<br> 需要具有灵力能量池才可以进行购买与使用。</p><p>灵力攻击<br> 250<br> 在进行攻击时支付2点灵力，令你这次攻击具有法破。</p><p>释放灵压<br> C+1000<br> 你获得了主动释放灵压的能力，当你将体内的灵力释放出来时，所有拥有灵感视觉的生物以及灵体/虚体都能看到你宛如实质一般的强大能量。<br> 以一个标准动作消耗6点灵力使用，需要以自由动作维持，每轮维持需消耗1点灵力。<br> 效果：释放灵压后，以你为中心的60米范围区域对于其他所有具有灵感视觉的单位或者灵体/虚体而言是一个B级别的困难地形环境，这同时是一个B级诅咒来源的负面效果。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',22)])])}const m=a(o,[["render",b]]);export{f as __pageData,m as default};
